// =============================================================================
// Permission Checking
// =============================================================================

const ROLE_HIERARCHY: Record<string, number> = {
  viewer: 0,
  staff: 1,
  manager: 2,
  accountant: 3,
  admin: 4,
};

function hasMinimumRole(userRole: string, minimumRole: string): boolean {
  return (ROLE_HIERARCHY[userRole] ?? 0) >= (ROLE_HIERARCHY[minimumRole] ?? 0);
}

function checkPermissions(
  tool: GeneratedAITool,
  context: ExecutionContext
): { allowed: boolean; reason?: string } {
  // Check minimum role
  if (!hasMinimumRole(context.userRole, tool.metadata.permissions.minimumRole)) {
    return {
      allowed: false,
      reason: `Requires minimum role: ${tool.metadata.permissions.minimumRole}`,
    };
  }

  // TODO: Check specific permissions against user's permission set
  // For now, role check is sufficient

  return { allowed: true };
}

// =============================================================================
// Tool Executor Factory
// =============================================================================

export function createToolExecutor(config: ToolExecutorConfig) {
  const { trpcCaller, cache, rateLimiter } = config;

  /**
   * Execute a tool by name with parameters
   */
  async function executeTool(
    toolName: string,
    parameters: unknown,
    context: ExecutionContext
  ): Promise<ExecutionResult> {
    const startTime = Date.now();

    // Get tool definition
    const tool = AI_TOOLS_BY_NAME.get(toolName);
    if (!tool) {
      return {
        success: false,
        error: {
          code: 'TOOL_NOT_FOUND',
          message: `Unknown tool: ${toolName}`,
          retryable: false,
        },
      };
    }

    // Check if tool is enabled
    if (!tool.metadata.enabled) {
      return {
        success: false,
        error: {
          code: 'TOOL_DISABLED',
          message: `Tool is disabled: ${toolName}`,
          retryable: false,
        },
      };
    }

    // Check permissions
    const permCheck = checkPermissions(tool, context);
    if (!permCheck.allowed) {
      return {
        success: false,
        error: {
          code: 'PERMISSION_DENIED',
          message: permCheck.reason || 'Permission denied',
          retryable: false,
        },
      };
    }

    // Check rate limit
    if (rateLimiter) {
      const limitCheck = await rateLimiter.check(toolName, context);
      if (!limitCheck.allowed) {
        return {
          success: false,
          error: {
            code: 'RATE_LIMITED',
            message: 'Rate limit exceeded. Please try again later.',
            retryable: true,
            details: { retryAfterMs: limitCheck.retryAfterMs },
          },
        };
      }
    }

    // Validate parameters
    const schema = VALIDATION_SCHEMAS[toolName];
    if (schema) {
      const parseResult = schema.safeParse(parameters);
      if (!parseResult.success) {
        return {
          success: false,
          error: {
            code: 'VALIDATION_ERROR',
            message: 'Parameter validation failed',
            retryable: false,
            details: parseResult.error.flatten(),
          },
        };
      }
      parameters = parseResult.data;
    }

    // Check cache for read operations
    // Note: Cached data is already output-shaped (we store shaped results)
    if (cache && tool.metadata.cache?.enabled && tool.metadata.method === 'GET') {
      const cacheKey = buildCacheKey(toolName, parameters, context);
      const cached = await cache.get(cacheKey);
      if (cached !== null) {
        return {
          success: true,
          data: cached,
          fromCache: true,
          executionTimeMs: Date.now() - startTime,
          outputShaping: {
            applied: !!tool.metadata.output,
            fieldsRedacted: 0, // Already redacted when cached
            itemsLimited: 0,
            tokensTruncated: false,
          },
        };
      }
    }

    // Execute tool
    try {
      const rawResult = await executeToolImplementation(toolName, parameters, context, trpcCaller);

      // Apply output shaping BEFORE caching or returning
      // This ensures redacted data is never stored or logged
      const outputConfig = tool.metadata.output as OutputConfig | undefined;
      const { data: shapedResult, stats: shapingStats } = applyOutputShaping(rawResult, outputConfig);

      // Cache the SHAPED result (not raw) if enabled
      if (cache && tool.metadata.cache?.enabled && tool.metadata.method === 'GET') {
        const cacheKey = buildCacheKey(toolName, parameters, context);
        await cache.set(cacheKey, shapedResult, tool.metadata.cache.ttlSeconds);
      }

      return {
        success: true,
        data: shapedResult,
        preview: context.dryRun,
        executionTimeMs: Date.now() - startTime,
        outputShaping: {
          applied: !!outputConfig,
          fieldsRedacted: shapingStats.fieldsRedacted,
          itemsLimited: shapingStats.itemsLimited,
          tokensTruncated: shapingStats.tokensTruncated,
        },
      };
    } catch (error) {
      const trpcError = error as TRPCError;
      return {
        success: false,
        error: {
          code: trpcError.code || 'EXECUTION_ERROR',
          message: trpcError.message || 'Tool execution failed',
          retryable: isRetryableError(trpcError),
          details: trpcError.cause,
        },
        executionTimeMs: Date.now() - startTime,
      };
    }
  }

  return { executeTool };
}

function buildCacheKey(
  toolName: string,
  parameters: unknown,
  context: ExecutionContext
): string {
  const tool = AI_TOOLS_BY_NAME.get(toolName);
  const varyBy = tool?.metadata.cache?.varyBy || [];

  const keyParts = [
    `ai:tool:${toolName}`,
    `org:${context.organizationId}`,
  ];

  if (varyBy.length > 0 && typeof parameters === 'object' && parameters !== null) {
    for (const key of varyBy) {
      const value = (parameters as Record<string, unknown>)[key];
      if (value !== undefined) {
        keyParts.push(`${key}:${JSON.stringify(value)}`);
      }
    }
  } else {
    keyParts.push(`params:${JSON.stringify(parameters)}`);
  }

  return keyParts.join(':');
}

function isRetryableError(error: TRPCError): boolean {
  const nonRetryableCodes = ['BAD_REQUEST', 'UNAUTHORIZED', 'FORBIDDEN', 'NOT_FOUND'];
  return !nonRetryableCodes.includes(error.code);
}

